（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:29+00:00", "source_pdf_sha1": "614cedc9a009", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "507", "s": "1001", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育行政學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00050', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-112-6c2680bf', 'sub-aboriginal-e0adf6cd-04', NULL, 'essay', '教育行政人員必須遵守行政倫理規範，而教育行政倫理可包括專業倫
